param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId)
$ErrorActionPreference='Stop';$root="$env:USERPROFILE\NoraPhase2U";$run=Join-Path $root $RunId;New-Item -ItemType Directory -Force $run|Out-Null;$source=Join-Path $run 'source';New-Item -ItemType Directory -Force $source|Out-Null
foreach($name in @('NoraPhase2MacdRuntimeV2.mqh','NoraPhase2MacdTesterCanaryV2.mq5')){Copy-Item (Join-Path $IncomingRoot $name) (Join-Path $source $name) -Force}
$editor='C:\Program Files\Darwinex MetaTrader 5\MetaEditor64.exe';$program=Join-Path $source 'NoraPhase2MacdTesterCanaryV2.mq5';$log=Join-Path $run 'compile.log';$ex5=Join-Path $source 'NoraPhase2MacdTesterCanaryV2.ex5';$p=Start-Process $editor -ArgumentList ('/compile:"'+$program+'" /log:"'+$log+'"') -PassThru;$p.WaitForExit();if(!(Test-Path $ex5)){throw 'MACD EX5 absent'};Copy-Item $ex5 (Join-Path $run 'NoraPhase2MacdTesterCanaryV2.ex5') -Force
